import sys
from collections import deque

class Solution:
    def height(self, root, target):
        if root is None or (root.val == target):
            return -1
        queue = deque([(root, 0)])
        seen = set()
        while queue:
            node, level = queue.popleft()
            if node in seen:
                continue
            if node.val == target:
                return level
            seen.add(node)
            if node.left:
                queue.append((node.left, level + 1))
            if node.right:
                queue.append((node.right, level + 1))
        return -1

