#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int height(Node* root, int target) {
        if (root == nullptr || (root->val == target))
            return -1;
        if (root->val == target)
            return 0;
        int left = height(root->left, target);
        if (left != -1)
            return left + 1;
        return height(root->right, target) + 1;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
cin.tie(nullptr);
cout.tie(nullptr);

    Node* root = nullptr;
    int n;
    cin >> n;
    int vals[n];
    for (int i = 0; i < n; i++) {
        cin >> vals[i];
        if (vals[i] == -1)
            root = nullptr;
        else {
            if (root == nullptr)
                root = new Node(vals[i]);
            else
                insert(root, vals[i]);
        }
    }

    int target;
    cin >> target;
    cout << height(root, target) << endl;

    return 0;
}
